parameters.message:
=<html>
<body style="font-family: Arial, sans-serif; max-width: 800px; margin: 0 auto; padding: 20px; color: #333;">

<h2 style="color: #0077B5; border-bottom: 2px solid #0077B5; padding-bottom: 10px;">
  🎯 Daily Job Digest — {{ $now.format('yyyy-MM-dd') }}
</h2>

{{ $json.jobs.sort((a, b) => {
  if (a.CATEGORY === 'STRONG MATCH' && b.CATEGORY !== 'STRONG MATCH') return -1;
  if (a.CATEGORY !== 'STRONG MATCH' && b.CATEGORY === 'STRONG MATCH') return 1;
  return b.SCORE - a.SCORE;
}).map(item => `
<div style="margin-bottom: 20px; padding: 15px; border-radius: 8px; border-left: 4px solid ${item.CATEGORY === 'STRONG MATCH' ? '#28a745' : '#ffc107'}; background-color: ${item.CATEGORY === 'STRONG MATCH' ? '#f0fff4' : '#fffdf0'};">
  <div style="display: flex; justify-content: space-between; align-items: center;">
    <span style="font-weight: bold; font-size: 16px;">${item.TITLE}</span>
    <span style="padding: 3px 10px; border-radius: 12px; font-size: 12px; font-weight: bold; background-color: ${item.CATEGORY === 'STRONG MATCH' ? '#28a745' : '#ffc107'}; color: ${item.CATEGORY === 'STRONG MATCH' ? 'white' : '#333'};">
      ${item.CATEGORY} — Score: ${item.SCORE}
    </span>
  </div>
  <div style="margin-top: 5px; color: #555;">
    🏢 ${item.COMPANY} &nbsp;|&nbsp; 📍 ${item.LOCATION} &nbsp;|&nbsp; 📅 ${item.POSTED}
  </div>
  <div style="margin-top: 5px; color: #555;">
    📄 Contract: ${item.CONTRACT} &nbsp;|&nbsp; 🌐 Language: ${item.LANGUAGE}
  </div>
  <div style="margin-top: 5px; color: #666; font-style: italic; font-size: 13px;">
    ${item['MATCH REASON'] || ''}
  </div>
  <div style="margin-top: 10px;">
    <a href="${item.URL}" style="background-color: #0077B5; color: white; padding: 6px 14px; text-decoration: none; border-radius: 4px; font-size: 13px;">
      Apply on LinkedIn →
    </a>
  </div>
</div>
`).join('')}}

<hr style="margin-top: 30px;">
<p style="color: #999; font-size: 12px; text-align: center;">
  Generated by your Job Search Agent • {{ $now.format('yyyy-MM-dd') }}
</p>

</body>
</html>

